INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-b20a8cf8-moex-00584', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '車禍現場跡證之處理原則，下列敘述那些正確？①應注意碰撞接觸面轉印型態痕跡及轉移跡證，', '["應採集現場遺留之油漆片、玻璃片及塑（橡）膠片，並妥善保存", "採取 附著或刮擦於車體上之油漆痕或塑（橡）膠，應避免刮取至車體底漆部位", "採取不同部位之油 漆痕時，應用同一件工具採取  ⑤涉案車輛均屬同色系外觀時，得採取一方車輛之標準漆送鑑", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00585', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關犯罪偵查的原理，下列敘述何者正確？①犯罪剖繪著重在有形跡證，依案發時間、現場跡證、', '["現場重建著重在行為跡證分析，從中找出相同模式，提供犯罪偵查方 向", "犯罪嫌疑人、犯罪手法及犯罪工具具有特殊性和穩定性", "犯罪嫌疑人犯案常具有連續性 ⑤犯罪現場會反映出犯罪者的人格特質", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00586', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關犯罪偵查，下列敘述何者正確？①犯罪偵查是偵查機關為提起公訴追訴犯罪的準備活動  ②', '["偵查的目的主要在蒐集證據，以 釐清有無犯罪之虞", "預防性跟監係屬偵查作為  ⑤偵查之開始是以犯罪事實存在為前提", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00587', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '關於各級警察機關專案小組之組成及權責，下列敘述何者錯誤？', '["設於內政部警政署者，由署長為召集人，並邀同相關警察局局長及刑警大隊大隊長參加", "設於直轄市警察局者，由局長或主管刑事業務之副局長親自主持或責由刑警大隊大隊長為召集 人，並邀同相關分局分局長參加", "設於警察分局者，由分局長或副分局長親自主持或責由偵查隊隊長為召集人，並邀同相關分局 偵查隊隊長參加", "專案小組成立後，由召集人統一指揮督導偵查工作，並將有關之證據、資料及情報統一交由小 組保管、運用及處理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00588', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '關於送達之規定，下列敘述何者正確？', '["送達人應製作送達證書，交應受送達人簽名、蓋章並按指印", "如未獲會晤應受送達人者，得將文書交予有辨別事理能力之同居人或受僱人代收", "如未獲會晤應受送達人或其同居人或受僱人者，得將文書留置於送達地之自治或警察機關", "應受送達人無法律上理由而拒絕收領者，得將通知書寄存於送達處所，將送達情形於送達證書 記明後附卷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00589', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '關於犯罪嫌疑人及證人之詢問規定，下列敘述何者錯誤？', '["詢問犯罪嫌疑人時應全程連續錄音", "詢問證人時應全程連續錄音", "司法警察官詢問犯罪嫌疑人，原則上不得於夜間行之", "司法警察官詢問證人，原則上不得於夜間行之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00590', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '關於拘提、逮捕之規定，下列敘述何者正確？', '["立法委員，除現行犯、通緝犯外，在會期中，非經立法院之許可，不得逮捕", "鄉民代表，除現行犯外，在會期內，非經鄉民代表會之同意，不得逮捕", "依刑事訴訟法第76條規定執行拘提時，應出示身分證件，並即告知本人及其家屬，得選任辯護人 到場", "依刑事訴訟法第 88 條之 1 規定執行拘提時，應出示身分證件，並即告知本人及其家屬，得選 任辯護人到場"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00591', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '關於司法警察官執行夜間搜索之規定，下列敘述何者正確？', '["日間已開始搜索或扣押者，不必報經檢察官許可，仍得繼續至夜間", "假釋人或緩刑人住居或使用之處所，夜間亦得入內搜索", "常用為賭博行為之處所，有急迫情形時，夜間亦得入內搜索", "夜間搜索之時段為午後11時至翌日午前8時"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00592', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '關於移送遞解之規定，下列敘述何者正確？', '["警察分局對於少年觸犯刑罰法律之行為，使用少年事件報告書", "警察分局對於單純之少年協尋案件，使用少年協尋案件移送書", "解送途中，得在監看而不與聞之控制下，許可被告探親或購物", "解送人犯在2名以下者，派解送員警2人，3名以上者，每增加人犯1名，得加派員警1人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00593', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '關於檢警聯繫之規定，下列敘述何者正確？', '["司法警察官或司法警察執行職務，發生法律上之疑義時，應以書面請求檢察官解答或指示", "司法警察機關報請檢察官核發偵查指揮書，帶同受羈押之被告外出繼續查證者，應於當日下午 12時前解交檢察官", "司法警察官或司法警察需經檢察官同意始得於夜間詢問人犯者，應以電話、傳真或其他適當方 式報請檢察官許可", "檢察事務官執行搜索或扣押時，得經檢察官許可後，請求當地警察機關協助，受請求之警察機 關不得拒絕"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
